import{_ as t,o,c as a,ae as s}from"./chunks/framework.BGHOrOyn.js";const f=JSON.parse(`{"title":"How to inspect and copy an element's CSS the easy way","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/tooling/css/how-to-inspect-and-copy-an-elements-css-the-easy-way.md","filePath":"software-engineering/tooling/css/how-to-inspect-and-copy-an-elements-css-the-easy-way.md"}`),n={name:"software-engineering/tooling/css/how-to-inspect-and-copy-an-elements-css-the-easy-way.md"};function i(c,e,l,r,h,p){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="how-to-inspect-and-copy-an-element-s-css-the-easy-way" tabindex="-1">How to inspect and copy an element&#39;s CSS the easy way <a class="header-anchor" href="#how-to-inspect-and-copy-an-element-s-css-the-easy-way" aria-label="Permalink to &quot;How to inspect and copy an element&#39;s CSS the easy way&quot;">​</a></h1><p>Here are simple steps you can do to inspect and copy the CSS of an element from a website.</p><h2 id="with-css-scan-chrome-firefox-safari-and-edge" tabindex="-1">With CSS Scan (Chrome, Firefox, Safari, and Edge): <a href="#with-css-scan-chrome-firefox-safari-and-edge" id="with-css-scan-chrome-firefox-safari-and-edge"></a> <a class="header-anchor" href="#with-css-scan-chrome-firefox-safari-and-edge" aria-label="Permalink to &quot;With CSS Scan (Chrome, Firefox, Safari, and Edge): &lt;a href=&quot;#with-css-scan-chrome-firefox-safari-and-edge&quot; id=&quot;with-css-scan-chrome-firefox-safari-and-edge&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>CSS Scan is by far the easiest way to copy an element’s CSS nowadays.</p><p>It’s simple, it works on every website, and it’s fast.</p><p>It’s available on all of the four browsers above (Chrome, Firefox, Safari, and Edge) as an extension.</p><p>To copy the CSS code of any element with <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">CSS Scan</a>, click on the element you want to copy.</p><p>It’s as simple as that. A single click and it’s yours.</p><p>Once the code is copied, you can paste it anywhere. And it copies not only the selected element but also all its child elements, pseudo-classes, and pseudo-elements.</p><p><a href="https://getcssscan.com/?ref=blog-1" target="_blank" rel="noreferrer"><img src="https://d33wubrfki0l68.cloudfront.net/d307435949d777c8e94c8225531ce3de19809f8e/a31a7/assets/images/copy-css.gif" alt="Copying CSS with CSS Scan is as easy as a single click"></a></p><p>And any element that you hover over, you’ll instantly inspect its CSS code, so it’ll save you a lot of time.</p><p>To use the extension, you can try it out a free demo on the <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">home page</a>.</p><h3 id="on-chrome-without-css-scan" tabindex="-1">On Chrome (without CSS Scan): <a href="#on-chrome-without-css-scan" id="on-chrome-without-css-scan"></a> <a class="header-anchor" href="#on-chrome-without-css-scan" aria-label="Permalink to &quot;On Chrome (without CSS Scan): &lt;a href=&quot;#on-chrome-without-css-scan&quot; id=&quot;on-chrome-without-css-scan&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>First, hover over the element you want to copy.</p><p>Then, right-click on it and choose the option “Inspect”.</p><p>It should look like this:</p><p><img src="https://d33wubrfki0l68.cloudfront.net/4b140d6362edad687292423157422a6bf5d3b7c4/d8e26/assets/images/devtools-min.jpg" alt="Chrome Devtools"></p><p>On the left side is the HTML DOM tree, and on the right side, the CSS styles of the selected element.</p><p>Having the right element selected on the HTML DOM tree, right-click on it and choose “Copy” &gt; “Copy styles”.</p><p><img src="https://d33wubrfki0l68.cloudfront.net/2609500d74a7729f99920c744d807d6cf5302d1c/e8304/assets/images/copy-styles-devtools-min.jpg" alt="Chrome Devtools Copy styles"></p><p>And done, the CSS was copied! That’s how you copy CSS from “Inspect element”.</p><p>⚠️ The biggest downsides of this approach are that:</p><ul><li>it doesn’t copy child elements (you’ll have to copy element by element, while with <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">CSS Scan</a> you can copy thousands of elements with a single click)</li><li>it doesn’t copy the element’s pseudo-classes (such as :hover, :active, etc) styles, which are special states, and for example, can be used to change a button’s color when the user’s pointer hovers over it, and many other purposes</li><li>it copies all CSS variables declared on the :root (even if they aren’t used on the selected element), polluting the code depending on the website.</li><li>it might take some time if you need to copy lots of elements.</li></ul><p>While with <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">CSS Scan</a>, you can copy not only the selected element but also all its child elements, their pseudo-classes (:hover, :active, etc) styles, all the computed CSS variables, and copy all the elements you want in a faster and easier way - without making all these steps, again, and again.</p><h4 id="on-firefox-without-css-scan" tabindex="-1">On Firefox (without CSS Scan): <a href="#on-firefox-without-css-scan" id="on-firefox-without-css-scan"></a> <a class="header-anchor" href="#on-firefox-without-css-scan" aria-label="Permalink to &quot;On Firefox (without CSS Scan): &lt;a href=&quot;#on-firefox-without-css-scan&quot; id=&quot;on-firefox-without-css-scan&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>First, hover over the element you want to copy. Then, right-click on it and choose the option to Inspect Element.</p><p><img src="https://d33wubrfki0l68.cloudfront.net/10d6a1474cee3bdbd2ab5064d75f2bf3ad675916/634b3/assets/images/ffx-devtools-min.jpg" alt="Firefox Devtools"></p><p>Firefox doesn’t have the option “Copy styles” that Chrome has so it’s a bit harder. On the right panel of the Devtools, it’s the CSS code (styles) we want to copy:</p><p><img src="https://d33wubrfki0l68.cloudfront.net/33e34058311b007780b59e094e144cd454cc1132/840d0/assets/images/ffx-devtools-styles-min.jpg" alt="Firefox Devtools (styles panel)"></p><p>As you can see, some rules are struck-through (canceled) because they are overridden by properties above that have higher CSS specificity.</p><p>To copy the element’s CSS on Firefox, you’ll need to select all the text that you’re seeing:</p><p><img src="https://d33wubrfki0l68.cloudfront.net/b4f4c7400e0c3231f2a06c7ff4cb939053419e83/fab46/assets/images/ffx-devtools-styles-copy-min.jpg" alt="Firefox Devtools"></p><p>But most of the time this is going to give you a very polluted and big code, and it doesn’t copy multiple elements at once.</p><p>If you want the code to be smaller and cleaner, you’ll have to remove the overridden rules and selectors by yourself, one by one, or use a tool like <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">CSS Scan</a>, which can also copy not only the selected element but also all its child elements with a single click.</p><h4 id="on-safari-without-css-scan" tabindex="-1">On Safari (without CSS Scan): <a href="#on-safari-without-css-scan" id="on-safari-without-css-scan"></a> <a class="header-anchor" href="#on-safari-without-css-scan" aria-label="Permalink to &quot;On Safari (without CSS Scan): &lt;a href=&quot;#on-safari-without-css-scan&quot; id=&quot;on-safari-without-css-scan&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>On Safari, the Development tools are hidden by default. So first, you’ll need to toggle it on.</p><p>To do that, open: Safari &gt; Preferences (⌘ ,) &gt; Advanced &gt; “Show Develop menu in menu bar”</p><p><img src="https://d33wubrfki0l68.cloudfront.net/d1b943bfec3ad7fae95cc04e00b3c11d1ad3be94/4a000/assets/images/safari-enabling-devtools-min.jpg" alt="Enabling Devtools on Safari"></p><p>Now, hover over the element you want to copy. Then, right-click on it and choose the option to Inspect Element. You just opened Safari Devtools:</p><p><img src="https://d33wubrfki0l68.cloudfront.net/25e0254ec19ca1293ff7252dd5faaef928136369/37cd3/assets/images/safari-devtools-min.jpg" alt="Safari&#39;s Devtools"></p><p>On the right panel of the Devtools, it’s the CSS code (styles) we want to copy.</p><p>As you can see, some rules are struck-through (canceled) because they are overridden by properties above that have higher CSS specificity.</p><p>To copy the element’s CSS on Safari, you’ll need to select all the text that you’re seeing:</p><p><img src="https://d33wubrfki0l68.cloudfront.net/3ef15ba20dbead93fabf3d74fa8647cbe4210637/893d3/assets/images/safari-devtools-styles-copy-min.jpg" alt="Safari Devtools (copying styles from the styles panel)"></p><p>But most of the time this is going to give you a very polluted and big code, and it doesn’t copy multiple elements at once.</p><p>If you want the code to be smaller and cleaner, you’ll have to remove the overridden rules and selectors by yourself, one by one, or use a tool like <a href="https://getcssscan.com/?ref=blog-2" target="_blank" rel="noreferrer">CSS Scan</a>, which can also copy not only the selected element but also all its child elements with a single click.</p>',46)])])}const u=t(n,[["render",i]]);export{f as __pageData,u as default};
